        "program_name": {"type": "string", "description": "Program this plan is for"},
        "price": {"type": "number", "description": "Monthly price"},
        "billing_period": {"type": "string", "enum": ["monthly", "quarterly", "biannual", "annual"], "description": "Billing cycle"},
        "description": {"type": "string", "description": "Plan description"}
    },
    "required": ["name"]
}

